import React          from "react";
import ReactDom       from "react-dom";
import Voodoo         from "react-voodoo";
import {RadialSelect} from "../comps/(*).js";
import homeStyles     from "./Home/(**/*).js";

const allSamples = [
	{
		label      : "TinderLike swiper",
		path       : "./samples/TinderLike/dist/static/index.html",
		description: "Tinder-style swipe cards with native-feel spring physics and gesture recognition",
		github     : "https://github.com/react-voodoo/react-voodoo-samples/tree/master/samples/TinderLike",
		sandbox    : "https://codesandbox.io/s/tinder-like-card-swiper-1735w"
	},
	{
		label      : "Swipeable Menu",
		path       : "./samples/AndroidMenu/dist/static/index.html",
		description: "Android-style radial menu with smooth swipe transitions and snap-to-item inertia",
		github     : "https://github.com/react-voodoo/react-voodoo-samples/tree/master/samples/AndroidMenu",
		sandbox    : "https://codesandbox.io/s/android-style-menu-bhn1n"
	},
	{
		label      : "Swipeable cards",
		path       : "./samples/Cards/dist/static/index.html",
		description: "Swipeable card stack with additive animations composing position, rotation and scale",
		github     : "https://github.com/react-voodoo/react-voodoo-samples/tree/master/samples/Cards",
		sandbox    : "https://codesandbox.io/s/react-voodoo-demo-cards-fmpt2?file=/src/comps/SwipeableCard.js"
	},
	{
		label      : "3d Cubes",
		path       : "./samples/Cubes/dist/static/index.html",
		description: "CSS 3D cube faces driven by a single scroll axis — no canvas, pure DOM transforms",
		github     : "https://github.com/react-voodoo/react-voodoo-samples/tree/master/samples/Cubes",
		sandbox    : "https://codesandbox.io/s/react-voodoo-cube-demo-7d65t"
	},
	//{
	//	label      : "Goo balls",
	//	path       : "./samples/Goo/dist/static/index.html",
	//	github     : "https://github.com/react-voodoo/react-voodoo-samples/tree/master/samples/Goo",
	//	description: "Multitouch goo balls with SVG filter blobs, each finger tracked on an independent axis"
	//}
]
const allSlides  = [
	{
		label      : " React-Voodoo",
		title      : "React-Voodoo",
		description: <div className={"doc-content"}>
			<p className={"tagline"}>
				A fast, additive &amp; swipeable tween engine for React.
			</p>
			<ul className={"feature-list"}>
				<li><strong>Delta-based</strong> — layer animations additively; no conflicts between tweens</li>
				<li><strong>Direct DOM</strong> — bypasses React's render loop for buttery 60 fps</li>
				<li><strong>Swipeable</strong> — predictive inertia, snap points, and looping axes</li>
				<li><strong>SSR-ready</strong> — works with React 16 / 17 / 18</li>
				<li><strong>Multi-unit</strong> — mix %, px, vw via CSS calc() in one value</li>
				<li><strong>Composable</strong> — nest tweeners, share axes across components</li>
			</ul>
			<p className={"doc-note"}>
				Spin the wheel to navigate. Scroll or drag down to browse samples.
			</p>
		</div>,
		link       : "https://github.com/react-voodoo/react-voodoo"
	},
	{
		label : "Samples",
		goDown: true
	},
	{
		label      : "Docs",
		title      : "API Reference",
		description: <div className={"doc-content api-ref"}>
			<section className={"doc-section"}>
				<h3>Install</h3>
				<pre className={"code-block"}>npm install react-voodoo</pre>
			</section>

			<section className={"doc-section"}>
				<h3>Quick Start</h3>
				<pre className={"code-block"}>{
					`import Voodoo from 'react-voodoo';

const tweens = [{
  from: 0, duration: 200,
  apply: { opacity: 1, transform: [{ translateY: "-100px" }] }
}];

export default () => {
  const [tweener, ViewBox] = Voodoo.hook();
  return (
    <ViewBox>
      <Voodoo.Axis axe="scroll" size={200} />
      <Voodoo.Node id="box" axes={{ scroll: tweens }}>
        <div>Animated!</div>
      </Voodoo.Node>
      <Voodoo.Draggable yAxis="scroll">
        <div className="drag-area" />
      </Voodoo.Draggable>
    </ViewBox>
  );
}`
				}</pre>
			</section>

			<section className={"doc-section"}>
				<h3>Tween Descriptor</h3>
				<pre className={"code-block"}>{
					`{
  from:     0,          // start position on timeline
  duration: 200,        // length on the axis
  apply: {
    opacity:   1,
    transform: [{ translateX: "100px" }],
    filter:    { blur: "5px" }
  },
  easeFn:   "easeInOutCubic",
  entering: (delta) => { /* axis entered range */ },
  moving:   (pos, prev, delta) => {},
  leaving:  (delta) => {}
}`
				}</pre>
			</section>

			<section className={"doc-section"}>
				<h3>Multi-unit Values</h3>
				<pre className={"code-block"}>{
					`// Array = CSS calc() sum
width: ["50%", "10vw", "-50px"]
// → calc(50% + 10vw - 50px)

// Applies delta to each unit independently
apply: { width: ["-20%", "20px"] }`
				}</pre>
			</section>

			<section className={"doc-section"}>
				<h3>Axis &amp; Inertia</h3>
				<pre className={"code-block"}>{
					`<Voodoo.Axis
  axe="scroll"
  size={1000}
  defaultPosition={0}
  inertia={{
    snapToBounds: true,
    wayPoints: [{ at: 0 }, { at: 500 }, { at: 1000 }],
    willSnap: (index, waypoint) => {},
    onSnap:   (index, waypoint) => {},
    shouldLoop: (pos, delta) => jumpValue | null
  }}
/>`
				}</pre>
			</section>

			<section className={"doc-section"}>
				<h3>Imperative Control</h3>
				<pre className={"code-block"}>{
					`const [tweener] = Voodoo.hook();

// Animate to position with easing
tweener.axes.scroll.scrollTo(500, 300, "easeInOutCubic");

// Instantly jump
tweener.axes.scroll.scrollTo(0, 0);`
				}</pre>
			</section>
		</div>,
		link       : "https://github.com/react-voodoo/react-voodoo/tree/master/doc",
	}
]


const initialSampleIndex = allSamples.findIndex(s => (("sample/" + s.label) === decodeURI(location.hash.substring(1)))),
      onBot              = location.hash.substring(1).startsWith("sample/");

export default () => {
	let [tweener, ViewBox]          = Voodoo.hook({ enableMouseDrag: true, dragDirectionLock: true }),
	    [atTop, setAtTop]           = React.useState(!onBot),
	    [curItems, setCurItems]     = React.useState(atTop ? allSlides : allSamples),
	    [cItemIndex, setCItemIndex] = React.useState(onBot && initialSampleIndex || 0),
	    cItem                       = React.useMemo(
		    () => curItems[cItemIndex],
		    [cItemIndex, curItems]
	    ),
	    [viewMode, setViewMode]     = React.useState("mobile"),
	    styles                      = React.useMemo(
		    () => ({
			    pageSwipe: {
				    axis: [
					    {
						    from    : 45,
						    duration: 1,
						    entering( move ) {
							    setAtTop(move < 0);
							    let cMenu = move < 0 ? allSlides : allSamples;
							    setCurItems(cMenu);
							    setCItemIndex(0)
							    if ( move < 0 )
								    location.hash = "#";
						    }
					    }
				    ]
			    },
			    ...(homeStyles[viewMode]),
			
			    pageInertia: {
				    wayPoints: [{ at: 0 }, { at: 50 }]
			    }
		    }), [viewMode]),
	    setSampleIndex              = ( index ) => {
		    if ( atTop ) {
			    location.hash = "#";
			    setCItemIndex(index)
		    }
		    else {
			    location.hash = "#sample/" + curItems[index].label;
			    setCItemIndex(index)
		    }
	    };
	React.useEffect(
		() => {
			//let onResize = e => setViewMode(window.innerWidth > 700 ? "desktop" : "mobile")
			let onScroll = e => tweener.axes.pageSwipe.scrollTo(e.deltaY > 0 ? 50 : 0, 250, "ease-in-out-cubic")
			//window.addEventListener("resize", onResize)
			window.addEventListener("wheel", onScroll, { passive: true });
			
			return e => {
				//window.removeEventListener("resize", onResize);
				window.removeEventListener("wheel", onScroll);
			}
		},
		[]
	);
	return <ViewBox className={"Home"}>
		
		<Voodoo.Axis
			axe={"pageSwipe"}
			size={100}
			scrollableWindow={100}
			defaultPosition={atTop ? 0 : 50}
			items={styles.pageSwipe.axis}
			inertia={styles.pageInertia}
		/>
		{/*<GithubCorner/>*/}
		<Voodoo.Draggable className={"page"}
			//xHook={styles.inverse}
			              yAxis={"pageSwipe"}>
			<Voodoo.Node
				id={"header"}
				axes={styles.header.axes}
				style={styles.header.style}>
				<div className={"header"}>
					<div className={"description"} onClick={e => tweener.axes.pageSwipe.scrollTo(0, 250)}>
						<h1>react-voodoo </h1>
					</div>
				</div>
			</Voodoo.Node>
			<Voodoo.Node
				id={"homeBlock"}
				axes={styles.homeBlock.axes}
				style={styles.homeBlock.style}>
				<div className={"homeBlock"}>
					<div className={"description"}>
						<h2>
							{cItem?.title}
						</h2>
						<div>
							{cItem?.description}
						</div>
						{
							cItem?.link &&
							<a href={cItem.link} target={"_blank"}>
								{cItem.link}
							</a>
						}
						<br/>
					</div>
					<div className={"down"} onClick={e => tweener.axes.pageSwipe.scrollTo(50, 250)}>▼</div>
				</div>
			</Voodoo.Node>
			<Voodoo.Node
				id={"RadialSelect"}
				axes={styles.RadialSelect.axes}
				style={styles.RadialSelect.style}>
				<div>
					<RadialSelect
						//key={atTop + ""}
						onChange={( item, i ) => {
							setSampleIndex(i);
							item.goDown && tweener.axes.pageSwipe.scrollTo(50, 250)
						}}
						selectedIndex={cItemIndex}
						items={curItems}/>
				</div>
			</Voodoo.Node>
			<Voodoo.Node
				id={"desk"}
				axes={styles.desk.axes}
				style={styles.desk.style}>
				<div className={"desk"}>
					<div className={"menu"}>
						{
							allSamples.map(
								( sample, i ) =>
									<div
										key={i}
										className={"button " + (sample === cItem ? "fire" : "ice")}
										onClick={e => setSampleIndex(i)}>
										{sample.label}
									</div>
							)
						}
					</div>
					{
						!atTop && cItem &&
						<div className={"demo"}>
							<iframe src={cItem.path}/>
							<div className={"details"}>
								{
									cItem.path &&
									<a href={cItem.path} className={"codesandbox"}>
										<img src={require("App/assets/fullPage.png").default} draggable="false"/>
									</a>
								}
								{
									cItem?.github &&
									<a href={cItem.github} target={"_new"} className={"codesandbox"}>
										<img src={require("App/assets/github.png").default} draggable="false"/>
									</a>
								}
								{
									cItem?.sandbox &&
									<a href={cItem.sandbox} target={"_new"} className={"codesandbox"}>
										<img src={require("App/assets/codesandbox.png").default} draggable="false"/>
									</a>
								}
								<div className={"description"}>
									<span>
										{cItem?.description || ''}
									</span>
								</div>
							</div>
						</div>
					}
				
				</div>
			</Voodoo.Node>
		</Voodoo.Draggable>
	</ViewBox>
}

module.hot?.accept?.()
